var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TREASURE_DEBT_GAP_NULL","text":{"KOREA":"A-Yo!","JPN":"A-Yo!","ENG":"A-yo!","TWN":"A-Yo！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L4_1","type":"dialog","speaker":"TREASURE_DEBT_GAP_NULL","text":{"KOREA":"겁나 느린 너에게는 핸디캡을 줘! 내가 뒤로 달려도 네겐 절대로 안 져!","JPN":"のろまなお前にハンディーをやる！　後ろ向きに走っても勝ってやる！","ENG":"I'll go easy on you since you're so slow! I can beat you even if I run on one toe!","TWN":"速度太慢像龜爬，愛心氾濫讓讓你！倒著跑步也能贏，笑你無能又無力！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TREASURE_DEBT_GAP_NULL","text":{"KOREA":"울어봤자 돌아오는 건 산-타 할아버지의 텅-빈 주머니뿐!","JPN":"泣いたって、サンタさんから空っぽのプレゼント箱をもらうだけだぞー！","ENG":"You can pout, you can cry! But don't blame Santa if you're left high and dry!","TWN":"你要哭，你就哭，心裡委屈把淚滴！但若聖誕忘記你，別怪Santa沒在意！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이익… 멈추란 말이야아-!!","JPN":"ぐう……待って！！","ENG":"Ngh... Stop it!","TWN":"可惡……給我站住——！！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님이나 좀 멈춰요! 대체 어디까지 갈 셈이야?","JPN":"室長こそ待ってください！　いったいどこまで行くつもりなんです？","ENG":"You stop, Chief! How far are you going to chase that thing?!","TWN":"室長你也停一下吧！到底要追到哪裡去？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이렇게 소란 피우면 다른 사람들이-","JPN":"あんまり騒がしくすると、周りの人たちがー","ENG":"The others will notice all the noise–","TWN":"這樣吵鬧的話，其他人會——"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":" 으악!","JPN":" うわっ！","ENG":" Agh!","TWN":"呃啊——！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC"},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으으. 넘어져버렸어.","JPN":"うう、コケちゃった。","ENG":"Ugh. I tripped.","TWN":"呃呃。摔倒了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"죄, 죄송해요. 여기 바닥이 엄청 미끄러운 바람에.","JPN":"す、すみません。ここは地面が滑りやすくて。","ENG":"S-sorry. The floor here is super slippery.","TWN":"對、對不起。這裡的地板太滑了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이건… 비누? 대체 누가 수영장 바닥에 비누를 칠해 놓은 거야?","JPN":"これは……石鹸？　誰よ、プールの床に石鹸を塗ったのは！","ENG":"Is this... soap? Who coated the swimming pool floors with soap?","TWN":"這是……肥皂？到底是誰在泳池底下塗了肥皂？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"설마 했던 대어라니. 숱한 전장에서의 경험이 또다시 빛을 보는군.","JPN":"まさかこんな大きな獲物が釣れるとは。これまでの戦場での豊富な経験が、また実を結んだ瞬間だぜ。","ENG":"This is unexpected. My experience on a great many battlefields has brought me glory, once again.","TWN":"真沒想到會有這麼大的收穫。看來我那無數次戰場上的經驗再次派上用場了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"오늘은 운수가 좋아. 설마 이렇게 간단하게 현상수배범을 잡을 줄이야.","JPN":"今日は幸先がいい。まさか、こんなに簡単に指名手配犯を捕まえることになるとは。","ENG":"It's a lucky day. I didn't think it'd be this easy to catch a wanted criminal.","TWN":"運氣真好。沒想到這麼輕鬆就抓到了通緝犯？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"내 말이 맞지? 여자애들이면 무조건 수영장에 올 수밖에 없다니까?","JPN":"言っただろう？　女の子なら、必ずプールに来るって！","ENG":"I told you. Girls can't resist coming to the swimming pool.","TWN":"我說的沒錯吧？只要是女孩子，就一定會來游泳池的，對吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"후후. 각성 용병인 우리에게 이런 수싸움 정도야 간단한 일이지.","JPN":"ふふ、覚醒傭兵である私たちにとって、この程度の頭脳戦はお手の物よ。","ENG":"Ha ha. This is an easy numbers game for us Awakened mercenaries.","TWN":"呵呵呵。對於我們這些覺醒傭兵來說，這種小小的策略戰還不是小菜一碟？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"수싸움은 무슨! 대체 어떤 멍청이가 수영장 바닥을 비누로 칠할 생각을 해요?","JPN":"これのどこか頭脳戦ですか！　プールの床を石鹸で塗りたくろうなんておかしいですよ！","ENG":"What do you mean \\"numbers game\\"?! What kind of idiot coats the floor with soap?!","TWN":"什麼策略戰！到底是哪個蠢蛋會想到在游泳池底塗肥皂的？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이봐, 아가씨. 그런 멍청이 같은 작전에 걸려든 사람이 누군데 그래?","JPN":"おい、お嬢ちゃん。その変な作戦にひっかかったのはどこの誰かな？","ENG":"Hey, lady. You're the one who fell for that idiotic plan.","TWN":"喂，小丫頭，那是什麼樣的蠢蛋會中計呢？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"그래. 계속 비누칠만 하느라 좀 쑤셔서 죽는 줄 알았다고.","JPN":"そうよ、石鹸塗りも大変だったのよ。腰にくるし。","ENG":"Yeah. You know how annoying it was to soap the place all day?","TWN":"是啊，一直在搓肥皂，我都快累死了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"TREASURE_DEBT_GAP_NULL","text":{"KOREA":"바보. 멍청이. 머저리.","JPN":"バカ。アホ。マヌケ。","ENG":"Stupid. Fool. Loser.","TWN":"蠢蛋，笨蛋，笨蛋。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"아하하하하하-!!","JPN":"あははははは！","ENG":"Aha ha ha ha ha!","TWN":"哈哈哈哈哈哈——！！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_LAUGH"},{"id":"L36_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"아니, 누구야 이 녀석은!?","JPN":"って、誰なの？　こいつ！？","ENG":"Wait, who is this?!","TWN":"呃，這傢伙是誰！?"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"TREASURE_DEBT_GAP_NULL","text":{"KOREA":"바보. 바보. 바보.","JPN":"バカ、バカ、バカ。","ENG":"Stupid. Stupid. Stupid.","TWN":"笨蛋，笨蛋，笨蛋。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"음… 뭐, 상관없지 않아? 어차피 우린 현상금만 차지하면 그만이잖아.","JPN":"ふむ……まぁ気にしなくていいんじゃね？　俺たちは懸賞金が手に入ればそれでいいんだし。","ENG":"Wait... does it matter? We're just here for the bounty.","TWN":"嗯……算了，無所謂吧？反正我們只要拿到賞金就行了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그래. 저쪽도 정신 못 차리고 있으니 얼른 가서 현상금이나 회수하자고.","JPN":"ああ、あっちも混乱してるし、急いで懸賞金を回収しちまおうぜ。","ENG":"Yeah. And they're distracted, so let's go and get the bounty.","TWN":"好。趁對方還沒反應過來，趕緊過去把賞金收了吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그럼…","JPN":"それじゃあ……","ENG":"Then...","TWN":"這樣的話……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":" 으악!","JPN":" うわっ！","ENG":" Agh!","TWN":"呃啊！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_WHOOSH_05"},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하하하-! 꼴 좋다. 정작 본인들도 미끄러워서 못 걷고 있잖아?","JPN":"あははっ！　自分たちだって滑って身動きが取れてないじゃないですか！","ENG":"Ha ha ha! Serves them right. They're having trouble walking, too!","TWN":"哈哈哈——! 真是活該。結果你們自己也滑到沒辦法走了吧?"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TREASURE_DEBT_GAP_NULL","text":{"KOREA":"세 얼간이. 멍청이 셋. 바보 트리오.","JPN":"三人のおバカさん。アホ三人。おバカトリオ。","ENG":"Three idiots. Three dummies. Dumb, dumber, and dumbest.","TWN":"三個，笨蛋，三個，傻瓜。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TREASURE_DEBT_GAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"아하하하하하-!!","JPN":"あははははは！","ENG":"Aha ha ha ha ha!","TWN":"哈哈哈哈哈哈——！！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_LAUGH"},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"끄아아아악-!!","JPN":"クアアアアッ！！","ENG":"Gaaaah!","TWN":"呃啊啊啊——!!"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐야. 이 깡통은 놔두고 왜 저만 쏘는 거예요?","JPN":"ちょっと、どうしてあのボロ缶じゃなくて、私を撃つんですか？","ENG":"Hey! Why are you shooting me and not that metal box?!","TWN":"什麼啊。為什麼放著這個鐵桶不管，只打我？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그야 아가씨 목에는 현상금이 걸려 있잖아. 저 깡통한테는 쏴봤자 총알 낭비라고.","JPN":"それはお嬢ちゃんが賞金首だからだよ。あのボロ缶は撃ったところで弾を消費するだけだ。","ENG":"You have a bounty on you. So it would be a waste to shoot at that metal box.","TWN":"因為你可是有賞金的。對那個鐵桶開槍只是浪費子彈。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"3대 2에. 아가씨들은 별다른 무기도 없어. 포기하고 얌전히 이쪽으로 와.","JPN":"3対2、それにお嬢ちゃんたちには武器もない。大人しく捕まりな。","ENG":"It's three against two, and you two don't have any weapons. It would be wise of you to surrender.","TWN":"3對2。我看你們也沒有什麼像樣的武器。放棄吧，乖乖過來。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"으으. 알파트릭스에 알트 소대까지 제쳤는데 고작 비누 때문에 몰리다니.","JPN":"うう。アルファトリックスにアルト小隊も出し抜いておいて、石鹸なんかのせいで追い込まれるなんて。","ENG":"Ugh. We got past Alphatrix and ALT Squad just to get cornered by a bunch of soap-using idiots?","TWN":"呃呃。連阿爾法崔克斯和阿爾特小隊這兩關都過了，竟然因為區區肥皂……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"싫어. 저런 세 얼간이한테만큼은 죽어도 잡히고 싶지 않아…….","JPN":"嫌だ……あんなバカ3人組にだけは絶対に捕まりたくない……","ENG":"No. I don't want to get caught by those three idiots...","TWN":"不行。我死也不想被那三個笨蛋抓住……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"걱정 마, 유피. 미끄러워서 걷지 못한다면 수영해서 가면 그만이거든.","JPN":"安心して、ユピ。滑る床を歩けないなら、泳げばいいじゃない。","ENG":"Don't worry, Yuppie. If we can't walk, we can swim.","TWN":"別擔心，悠菲。如果路太滑走不了的話，那就游過去吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"바닥에서 수영을 어떻게 한다고 그래요?","JPN":"床を？　どうやって泳ぐんですか？","ENG":"How are we going to swim on the ground?","TWN":"在地板上怎麼游泳啊！？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"엣흠. 그럴 줄 알고 시그마 선장님이 바닥에서 수영하는 법을 배워왔지.","JPN":"コホン。こういうこともあろうかと、シグマ船長は床泳ぎの技法も学んでおいたんだよ。","ENG":"Ahem. This is why Captain Sigma learned how to swim on the ground.","TWN":"哼哼。我早就料到了，所以西格瑪船長學會了在地板上游泳的方法。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"따라 해 봐.","JPN":"真似してみて。","ENG":"Follow my lead.","TWN":"跟我學。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_LAMP"},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":" 흡. 하. 흡. 하!","JPN":" すう、はあ！　すう、はあ！","ENG":" Hmph. Hah. Hmph. Hah!","TWN":"呼，哈，呼，哈！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"흡. 하. 흡……","JPN":"すう、はあ！　すう……","ENG":"Hmph. Hah. Hmph...","TWN":"呼，哈，呼……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아니, 이거 어떻게 하는 거야?","JPN":"これ、本当に合ってます？","ENG":"Wait, how are you supposed to do this?","TWN":"不是，這個到底怎麼做到啊？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"어이. 거기 뭐하는 거야?","JPN":"おい、何をしているんだ？","ENG":"Hey, what are you doing there?","TWN":"喂。你在那做什麼？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"흡. 하. 흡. 하!","JPN":"すう、はあ！　すう、はあ！","ENG":"Hmph. Hah. Hmph. Hah!","TWN":"呼，哈，呼，哈！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님. 저만 두고 가지 마세요오……!","JPN":"室長、私を置いていかないで……！","ENG":"Chief, don't leave me behind...!","TWN":"室長，不要丟下我啊……！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};